def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    P = list(map(int, data[1:N+1]))

    rank = [0] * N
    used = [False] * N
    r = 1

    while True:
        max_score = -1
        max_indices = []

        for i in range(N):
            if not used[i] and P[i] > max_score:
                max_score = P[i]
                max_indices = [i]
            elif not used[i] and P[i] == max_score:
                max_indices.append(i)

        if not max_indices:
            break

        for idx in max_indices:
            rank[idx] = r
            used[idx] = True

        r += len(max_indices)

    for i in range(N):
        print(rank[i])

if __name__ == "__main__":
    main()
